def record_latency(self, latency_ms: float) -> None:
    self._latency_buffer.append(latency_ms)
    if len(self._latency_buffer) > self._LATENCY_BUFFER_MAX:
        self._latency_buffer = self._latency_buffer[-self._LATENCY_BUFFER_MAX:]

def record_status(self, status_code: int) -> None:
    if 200 <= status_code < 300:
        self.status_2xx += 1
    elif 300 <= status_code < 400:
        self.status_3xx += 1
    elif 400 <= status_code < 500:
        self.status_4xx += 1
    elif 500 <= status_code < 600:
        self.status_5xx += 1

def set_routing(self, config: RoutingConfig) -> None:
    """Set routing configuration. Raises if current config is locked."""
    if self._routing and self._routing.locked:
        raise RuntimeError("Cannot set routing: current config is locked")
    self._routing = config
    self._target_metrics = {}

def clear_routing(self) -> None:
    """Remove routing configuration. Raises if locked."""
    if self._routing and self._routing.locked:
        raise RuntimeError("Cannot clear routing: config is locked")
    self._routing = None

async def drain(self, timeout: float = 30.0) -> None:
    """Stop accepting new connections, wait for active ones to finish."""
    self._draining = True
    if self._active_connections > 0:
        try:
            await asyncio.wait_for(self._drain_event.wait(), timeout=timeout)
        except asyncio.TimeoutError:
            logger.warning(
                f"Adapter [{self._node.name}] drain timed out "
                f"with {self._active_connections} active"
            )

async def health_check(self) -> HealthCheck:
    """Check backend reachability. Uses HTTP for HTTP-mode, TCP otherwise."""
    if not self._backend.is_configured:
        return HealthCheck(
            node_name=self._node.name,
            verdict=HealthVerdict.UNKNOWN,
            detail="No backend configured",
            timestamp=_now_iso(),
        )
    if self._node.proxy_mode == ProxyMode.HTTP:
        return await self._http_health_check()
    return await self._tcp_health_check()

def _select_backend_named(
    self, request_data: bytes | None = None
) -> tuple[BackendTarget | None, str | None]:
    """Select a backend and return (target, target_name).

    target_name is the RoutingTarget.name (e.g. "stable", "canary") or None
    when no routing config is active.
    """
    if self._routing is None:
        return (self._backend if self._backend.is_configured else None, None)

    targets_by_name = {t.name: t for t in self._routing.targets}

    if self._routing.strategy in (RoutingStrategy.WEIGHTED, RoutingStrategy.CANARY):
        return self._select_weighted_named(self._routing.targets)
    elif self._routing.strategy == RoutingStrategy.HEADER and request_data:
        return self._select_by_header_named(request_data, self._routing, targets_by_name)

    return (self._backend if self._backend.is_configured else None, None)

def _select_by_header_named(
    self,
    request_data: bytes,
    config: RoutingConfig,
    targets_by_name: dict,
) -> tuple[BackendTarget, str | None]:
    """Route based on header value, returning (target, name)."""
    headers = self._parse_headers(request_data)
    for rule in config.rules:
        if headers.get(rule.header.lower()) == rule.value:
            t = targets_by_name.get(rule.target)
            if t:
                return BackendTarget(host=t.host, port=t.port), t.name
    # Fall back to default target
    t = targets_by_name.get(config.default_target)
    if t:
        return BackendTarget(host=t.host, port=t.port), t.name
    return self._backend, None

def _parse_headers(data: bytes) -> dict[str, str]:
    """Extract header key:value pairs from raw HTTP request bytes."""
    result: dict[str, str] = {}
    try:
        header_section = data.split(b"\r\n\r\n", 1)[0]
        lines = header_section.split(b"\r\n")
        # Skip request line (first line)
        for line in lines[1:]:
            if b":" in line:
                key, val = line.split(b":", 1)
                result[key.strip().decode("ascii", errors="replace").lower()] = (
                    val.strip().decode("ascii", errors="replace")
                )
    except Exception:
        pass
    return result

def _decrement_connections(self) -> None:
    self._active_connections -= 1
    if self._draining and self._active_connections <= 0:
        self._drain_event.set()

async def _pipe(
    reader: asyncio.StreamReader, writer: asyncio.StreamWriter
) -> None:
    """Copy bytes from reader to writer until EOF."""
    try:
        while True:
            data = await reader.read(65536)
            if not data:
                break
            writer.write(data)
            await writer.drain()
    except (ConnectionResetError, BrokenPipeError):
        pass

async def _read_http_message(reader: asyncio.StreamReader) -> bytes | None:
    """Read a full HTTP/1.1 message (headers + body via Content-Length)."""
    try:
        headers = await asyncio.wait_for(reader.readuntil(b"\r\n\r\n"), timeout=30.0)
    except (asyncio.TimeoutError, asyncio.IncompleteReadError, ConnectionResetError):
        return None

    content_length = 0
    for line in headers.split(b"\r\n"):
        if line.lower().startswith(b"content-length:"):
            try:
                content_length = int(line.split(b":", 1)[1].strip())
            except ValueError:
                pass
            break

    body = b""
    if content_length > 0:
        try:
            body = await asyncio.wait_for(
                reader.readexactly(content_length), timeout=30.0
            )
        except (asyncio.TimeoutError, asyncio.IncompleteReadError):
            return None

    return headers + body

def _parse_request_line(data: bytes) -> tuple[str, str]:
    """Extract method and path from the first line of an HTTP request."""
    try:
        first_line = data.split(b"\r\n", 1)[0].decode("ascii", errors="replace")
        parts = first_line.split(" ")
        if len(parts) >= 2:
            return parts[0], parts[1]
    except Exception:
        pass
    return "", ""

def _parse_status_code(data: bytes | None) -> int:
    """Extract status code from HTTP response."""
    if not data:
        return 0
    try:
        first_line = data.split(b"\r\n", 1)[0].decode("ascii", errors="replace")
        parts = first_line.split(" ")
        if len(parts) >= 2:
            return int(parts[1])
    except Exception:
        pass
    return 0

def __init__(self, adapter: Adapter):
    self._adapter = adapter
    self._server: asyncio.Server | None = None

def _handle_status(self) -> str:
    node = self._adapter.node
    backend = self._adapter.backend
    routing = self._adapter.routing
    result = {
        "node": node.name,
        "listening": f"{node.host}:{node.port}",
        "mode": str(node.proxy_mode),
        "backend": f"{backend.host}:{backend.port}" if backend.is_configured else None,
        "running": self._adapter.is_running,
    }
    if routing:
        result["routing_strategy"] = str(routing.strategy)
        result["routing_locked"] = routing.locked
    return json.dumps(result)

def _handle_routing(self) -> str:
    routing = self._adapter.routing
    if routing is None:
        backend = self._adapter.backend
        return json.dumps({
            "strategy": "single",
            "backend": f"{backend.host}:{backend.port}" if backend.is_configured else None,
        })
    return json.dumps(routing.model_dump())

def _get_current_canary_weight(self) -> int:
    """Get current canary weight from the adapter's routing config."""
    routing = self._adapter.routing
    if routing is None:
        return 0
    for t in routing.targets:
        if t.name == "canary":
            return t.weight
    return 0

def add_node(
    circuit: CircuitSpec,
    name: str,
    port: int = 0,
    proxy_mode: str = "http",
    contract: str = "",
    role: str = "service",
) -> CircuitSpec:
    """Add a node to the circuit. Auto-assigns port if not specified."""
    if circuit.node_by_name(name) is not None:
        raise ValueError(f"Node '{name}' already exists")
    if port == 0:
        port = _next_port(circuit)
    node = NodeSpec(name=name, port=port, proxy_mode=proxy_mode, contract=contract, role=role)
    return CircuitSpec(
        name=circuit.name,
        version=circuit.version,
        nodes=[*circuit.nodes, node],
        edges=list(circuit.edges),
    )

def remove_node(circuit: CircuitSpec, name: str) -> CircuitSpec:
    """Remove a node and all its edges from the circuit."""
    if circuit.node_by_name(name) is None:
        raise ValueError(f"Node '{name}' not found")
    return CircuitSpec(
        name=circuit.name,
        version=circuit.version,
        nodes=[n for n in circuit.nodes if n.name != name],
        edges=[e for e in circuit.edges if e.source != name and e.target != name],
    )

def add_edge(circuit: CircuitSpec, source: str, target: str, label: str = "") -> CircuitSpec:
    """Add a directed edge between two nodes."""
    if circuit.node_by_name(source) is None:
        raise ValueError(f"Source node '{source}' not found")
    if circuit.node_by_name(target) is None:
        raise ValueError(f"Target node '{target}' not found")
    for e in circuit.edges:
        if e.source == source and e.target == target:
            raise ValueError(f"Edge {source} -> {target} already exists")
    edge = EdgeSpec(source=source, target=target, label=label)
    return CircuitSpec(
        name=circuit.name,
        version=circuit.version,
        nodes=list(circuit.nodes),
        edges=[*circuit.edges, edge],
    )

def remove_edge(circuit: CircuitSpec, source: str, target: str) -> CircuitSpec:
    """Remove a directed edge."""
    found = False
    new_edges = []
    for e in circuit.edges:
        if e.source == source and e.target == target:
            found = True
        else:
            new_edges.append(e)
    if not found:
        raise ValueError(f"Edge {source} -> {target} not found")
    return CircuitSpec(
        name=circuit.name,
        version=circuit.version,
        nodes=list(circuit.nodes),
        edges=new_edges,
    )

def set_contract(circuit: CircuitSpec, node_name: str, contract_path: str) -> CircuitSpec:
    """Set the contract spec path for a node."""
    if circuit.node_by_name(node_name) is None:
        raise ValueError(f"Node '{node_name}' not found")
    new_nodes = []
    for n in circuit.nodes:
        if n.name == node_name:
            new_nodes.append(NodeSpec(
                name=n.name,
                host=n.host,
                port=n.port,
                proxy_mode=n.proxy_mode,
                contract=contract_path,
                role=n.role,
                management_port=n.management_port,
                metadata=dict(n.metadata),
            ))
        else:
            new_nodes.append(n)
    return CircuitSpec(
        name=circuit.name,
        version=circuit.version,
        nodes=new_nodes,
        edges=list(circuit.edges),
    )

def has_cycle(circuit: CircuitSpec) -> bool:
    """Check if the circuit's edge graph contains a cycle."""
    adj: dict[str, list[str]] = {n.name: [] for n in circuit.nodes}
    for e in circuit.edges:
        adj[e.source].append(e.target)

    WHITE, GRAY, BLACK = 0, 1, 2
    color: dict[str, int] = {name: WHITE for name in adj}

    def dfs(node: str) -> bool:
        color[node] = GRAY
        for neighbor in adj[node]:
            if color[neighbor] == GRAY:
                return True
            if color[neighbor] == WHITE and dfs(neighbor):
                return True
        color[node] = BLACK
        return False

    return any(dfs(name) for name, c in color.items() if c == WHITE)

def topological_sort(circuit: CircuitSpec) -> list[str]:
    """Return node names in topological order (dependencies first).

    Raises ValueError if the graph has a cycle.
    """
    if has_cycle(circuit):
        raise ValueError("Circuit contains a cycle")

    adj: dict[str, list[str]] = {n.name: [] for n in circuit.nodes}
    in_degree: dict[str, int] = {n.name: 0 for n in circuit.nodes}
    for e in circuit.edges:
        adj[e.source].append(e.target)
        in_degree[e.target] += 1

    queue = [name for name, deg in in_degree.items() if deg == 0]
    result: list[str] = []
    while queue:
        queue.sort()
        node = queue.pop(0)
        result.append(node)
        for neighbor in adj[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return result

def _next_port(circuit: CircuitSpec) -> int:
    """Find the next available port."""
    used = {n.port for n in circuit.nodes}
    for port in range(DEFAULT_PORT_START, DEFAULT_PORT_MAX + 1):
        if port not in used:
            return port
    raise RuntimeError("No available ports in range")

def dfs(node: str) -> bool:
    color[node] = GRAY
    for neighbor in adj[node]:
        if color[neighbor] == GRAY:
            return True
        if color[neighbor] == WHITE and dfs(neighbor):
            return True
    color[node] = BLACK
    return False

