def compute_mock_backends(
    circuit: CircuitSpec,
    live_nodes: set[str],
) -> dict[str, BackendTarget]:
    """Compute backend targets for mocked nodes.

    Returns a mapping of node_name -> BackendTarget pointing to the
    mock server's port for that node.
    """
    # Egress nodes are always mocked regardless of live_nodes
    effective_live = live_nodes - {n.name for n in circuit.egress_nodes}

    backends: dict[str, BackendTarget] = {}
    for node in circuit.nodes:
        if node.name in effective_live:
            continue

        service_port = node.port + 20000
        if service_port > 65535:
            service_port = node.port + 5000

        backends[node.name] = BackendTarget(host="127.0.0.1", port=service_port)

    return backends

def check_compatibility(
    provider: ServiceManifest,
    consumers: list[ServiceManifest],
    base_dir: str | Path = ".",
) -> CompatReport:
    """Check if a provider service is compatible with all consumers.

    For each consumer that depends on the provider:
    1. Load the consumer's expected_api for that dependency.
    2. Load the provider's api_spec.
    3. Verify expected paths/methods exist and schemas are structurally compatible.
    """
    report = CompatReport()
    base = Path(base_dir)

    provider_paths = (
        _load_api_paths(base, provider.api_spec) if provider.api_spec else {}
    )

    for consumer in consumers:
        for dep in consumer.dependencies:
            if dep.name != provider.name:
                continue
            if not dep.expected_api:
                continue

            expected_paths = _load_api_paths(base, dep.expected_api)
            _compare_paths(
                consumer.name, provider.name,
                expected_paths, provider_paths, report,
            )

    return report

def _load_api_paths(
    base: Path, spec_path: str
) -> dict[str, dict[str, Any]]:
    """Load OpenAPI paths from a spec file.

    Returns: {path: {METHOD: response_schema_or_None}}
    """
    full_path = base / spec_path
    if not full_path.exists():
        return {}
    with open(full_path) as f:
        if full_path.suffix in (".yaml", ".yml"):
            spec = yaml.safe_load(f)
        else:
            spec = json.load(f)
    if not spec or "paths" not in spec:
        return {}

    components = spec.get("components", {}).get("schemas", {})
    result: dict[str, dict[str, Any]] = {}
    for path_str, methods in spec.get("paths", {}).items():
        result[path_str] = {}
        for method, operation in methods.items():
            if method.startswith("x-") or method == "parameters":
                continue
            result[path_str][method.upper()] = _extract_response_schema(
                operation, components
            )
    return result

def _extract_response_schema(operation: dict, components: dict) -> Any:
    """Extract the success response schema from an operation."""
    responses = operation.get("responses", {})
    success = responses.get("200") or responses.get("201") or {}
    content = success.get("content", {}).get("application/json", {})
    schema = content.get("schema", {})
    if "$ref" in schema:
        ref_name = schema["$ref"].split("/")[-1]
        schema = components.get(ref_name, {})
    return schema or None

def _compare_paths(
    consumer: str,
    provider: str,
    expected: dict[str, dict[str, Any]],
    actual: dict[str, dict[str, Any]],
    report: CompatReport,
) -> None:
    """Compare expected paths/methods against actual."""
    for path, methods in expected.items():
        if path not in actual:
            for method in methods:
                report.add(CompatIssue(
                    consumer=consumer, provider=provider,
                    path=path, method=method, severity="error",
                    detail=f"Path '{path}' expected by {consumer} but not provided by {provider}",
                ))
            continue
        for method, expected_schema in methods.items():
            if method not in actual[path]:
                report.add(CompatIssue(
                    consumer=consumer, provider=provider,
                    path=path, method=method, severity="error",
                    detail=f"{method} {path} expected by {consumer} but not provided by {provider}",
                ))
                continue
            actual_schema = actual[path][method]
            if expected_schema and actual_schema:
                _compare_schemas(
                    consumer, provider, path, method,
                    expected_schema, actual_schema, report,
                )

def add(self, issue: CompatIssue) -> None:
    self.issues.append(issue)
    if issue.severity == "error":
        self.compatible = False

def load_circuit(project_dir: str | Path) -> CircuitSpec:
    """Load CircuitSpec from baton.yaml in the given directory."""
    path = Path(project_dir) / CONFIG_FILENAME
    if not path.exists():
        raise FileNotFoundError(f"No {CONFIG_FILENAME} found in {project_dir}")
    with open(path) as f:
        raw = yaml.safe_load(f)
    if raw is None:
        return CircuitSpec()
    return _parse_circuit(raw)

def load_circuit_from_services(
    project_dir: str | Path,
    service_dirs: list[str | Path] | None = None,
) -> CircuitSpec:
    """Derive CircuitSpec from service manifests.

    If service_dirs is None, discovers them from baton.yaml's 'services'
    key or by scanning subdirectories for baton-service.yaml files.
    """
    from baton.registry import derive_circuit, load_manifests

    base = Path(project_dir)
    if service_dirs is None:
        service_dirs = _discover_service_dirs(base)

    if not service_dirs:
        raise FileNotFoundError("No service directories found")

    manifests = load_manifests(service_dirs)

    circuit_name = "default"
    config_path = base / CONFIG_FILENAME
    if config_path.exists():
        with open(config_path) as f:
            raw = yaml.safe_load(f) or {}
        circuit_name = raw.get("name", "default")

    return derive_circuit(manifests, circuit_name=circuit_name)

def _discover_service_dirs(project_dir: Path) -> list[Path]:
    """Auto-discover service directories.

    1. Check baton.yaml for a 'services' list of paths.
    2. Otherwise, scan immediate subdirectories for baton-service.yaml.
    """
    from baton.manifest import MANIFEST_FILENAME

    config_path = project_dir / CONFIG_FILENAME
    if config_path.exists():
        with open(config_path) as f:
            raw = yaml.safe_load(f) or {}
        if "services" in raw:
            return [project_dir / s for s in raw["services"]]

    dirs = []
    if project_dir.is_dir():
        for child in sorted(project_dir.iterdir()):
            if child.is_dir() and (child / MANIFEST_FILENAME).exists():
                dirs.append(child)
    return dirs

def _parse_circuit(raw: dict) -> CircuitSpec:
    """Parse raw YAML dict into CircuitSpec."""
    nodes = []
    for n in raw.get("nodes", []):
        nodes.append(NodeSpec(**n))
    edges = []
    for e in raw.get("edges", []):
        edges.append(EdgeSpec(**e))
    return CircuitSpec(
        name=raw.get("name", "default"),
        version=raw.get("version", 1),
        nodes=nodes,
        edges=edges,
    )

def _serialize_circuit(circuit: CircuitSpec) -> dict:
    """Convert CircuitSpec to a YAML-serializable dict."""
    data: dict = {
        "name": circuit.name,
        "version": circuit.version,
    }
    if circuit.nodes:
        data["nodes"] = []
        for n in circuit.nodes:
            nd: dict = {"name": n.name, "port": n.port}
            if n.host != "127.0.0.1":
                nd["host"] = n.host
            if n.proxy_mode != "http":
                nd["proxy_mode"] = str(n.proxy_mode)
            if n.contract:
                nd["contract"] = n.contract
            if n.role != "service":
                nd["role"] = str(n.role)
            if n.metadata:
                nd["metadata"] = dict(n.metadata)
            data["nodes"].append(nd)
    if circuit.edges:
        data["edges"] = []
        for e in circuit.edges:
            ed: dict = {"source": e.source, "target": e.target}
            if e.label:
                ed["label"] = e.label
            data["edges"].append(ed)
    return data

def decide(self, adapter_state: AdapterState) -> CustodianAction:
    """Decide what repair action to take.

    - < FAILURE_THRESHOLD consecutive failures: restart service
    - >= FAILURE_THRESHOLD and has a command: replace with mock
    - No command (was already mock): escalate
    """
    if adapter_state.service.is_mock:
        return CustodianAction.ESCALATE

    if adapter_state.consecutive_failures < FAILURE_THRESHOLD * 2:
        return CustodianAction.RESTART_SERVICE
    else:
        return CustodianAction.REPLACE_SERVICE

async def _check_all(self) -> None:
    for name, adapter in self._adapters.items():
        adapter_state = self._state.adapters.get(name)
        if not adapter_state:
            continue

        health = await adapter.health_check()
        adapter_state.last_health_check = health.timestamp
        adapter_state.last_health_verdict = health.verdict

        if health.verdict == HealthVerdict.UNHEALTHY:
            adapter_state.consecutive_failures += 1
            if adapter_state.consecutive_failures >= FAILURE_THRESHOLD:
                await self._repair(name, adapter_state)
        elif health.verdict == HealthVerdict.HEALTHY:
            if adapter_state.consecutive_failures > 0:
                adapter_state.consecutive_failures = 0
            if adapter_state.status == NodeStatus.FAULTED:
                adapter_state.status = NodeStatus.ACTIVE

def format_table(snapshot: DashboardSnapshot) -> str:
    """Format snapshot as a human-readable table."""
    if not snapshot.nodes:
        return "No nodes in snapshot."

    header = f"{'Node':<14} {'Role':<10} {'Status':<10} {'Health':<10} {'Reqs':>6} {'Err%':>6} {'p50':>8} {'p95':>8} {'Routing'}"
    lines = [header, "-" * len(header)]

    for node in snapshot.nodes.values():
        err_pct = f"{node.error_rate * 100:.1f}%" if node.requests_total > 0 else "—"
        p50 = f"{node.latency_p50:.0f}ms" if node.latency_p50 > 0 else "—"
        p95 = f"{node.latency_p95:.0f}ms" if node.latency_p95 > 0 else "—"
        routing = node.routing_strategy or "single"
        if node.routing_locked:
            routing += " (locked)"

        lines.append(
            f"{node.name:<14} {node.role:<10} {node.status:<10} {node.health:<10} "
            f"{node.requests_total:>6} {err_pct:>6} {p50:>8} {p95:>8} {routing}"
        )

    return "\n".join(lines)

def _handle_topology(self) -> str:
    """Return circuit nodes and edges as JSON."""
    nodes = []
    for n in self._circuit.nodes:
        nodes.append({
            "name": n.name,
            "port": n.port,
            "role": str(n.role),
            "host": n.host,
        })
    edges = []
    for e in self._circuit.edges:
        edges.append({
            "source": e.source,
            "target": e.target,
            "label": e.label,
        })
    return json.dumps({"nodes": nodes, "edges": edges})

def _handle_signals(self, last_n: int = 50) -> str:
    """Return recent signals as JSON."""
    if not self._signal_aggregator:
        return json.dumps([])
    signals = self._signal_aggregator.query(last_n=last_n)
    return json.dumps([s.model_dump() for s in signals])

def _handle_signal_stats(self) -> str:
    """Return per-path signal statistics as JSON."""
    if not self._signal_aggregator:
        return json.dumps({})
    stats = self._signal_aggregator.path_stats()
    return json.dumps({
        path: {
            "path": s.path,
            "count": s.count,
            "avg_latency_ms": round(s.avg_latency_ms, 2),
            "error_count": s.error_count,
            "error_rate": round(s.error_rate, 4),
        }
        for path, s in stats.items()
    })

def __init__(self, project_dir: str | Path, circuit_name: str = "baton"):
    self._project_dir = Path(project_dir)
    self._circuit_name = circuit_name

def _detect_python_entry(self, service_dir: Path) -> list[str]:
    """Detect Python entry point from pyproject.toml or defaults."""
    pyproject = service_dir / "pyproject.toml"
    if pyproject.exists():
        content = pyproject.read_text()
        # Simple TOML parsing for [project.scripts]
        in_scripts = False
        for line in content.splitlines():
            if line.strip() == "[project.scripts]":
                in_scripts = True
                continue
            if in_scripts:
                if line.strip().startswith("["):
                    break
                if "=" in line:
                    # e.g. baton = "baton.cli:main"
                    val = line.split("=", 1)[1].strip().strip('"').strip("'")
                    module = val.split(":")[0]
                    return ["python", "-m", module]

    # Check for common entry points
    if (service_dir / "app.py").exists():
        return ["python", "app.py"]
    if (service_dir / "main.py").exists():
        return ["python", "main.py"]
    if (service_dir / "app" / "__init__.py").exists():
        return ["python", "-m", "app"]

    return ["python", "-m", "app"]

def _detect_node_entry(self, service_dir: Path) -> str:
    """Detect Node.js entry point from package.json or defaults."""
    pkg = service_dir / "package.json"
    if pkg.exists():
        data = json.loads(pkg.read_text())
        # Check scripts.start
        start_script = data.get("scripts", {}).get("start", "")
        if start_script and start_script.startswith("node "):
            return start_script.split("node ", 1)[1].strip()
        # Check main field
        main = data.get("main", "")
        if main:
            return main

    if (service_dir / "index.js").exists():
        return "index.js"
    if (service_dir / "server.js").exists():
        return "server.js"
    if (service_dir / "app.js").exists():
        return "app.js"

    return "index.js"

def __init__(self, project_dir: str | Path):
    self.project_dir = Path(project_dir)
    self._adapters: dict[str, Adapter] = {}
    self._controls: dict[str, AdapterControlServer] = {}
    self._process_mgr = ProcessManager()
