    self._state: CircuitState | None = None

def set_routing(self, node_name: str, config: RoutingConfig) -> None:
    """Set routing configuration on a node's adapter."""
    adapter = self._adapters.get(node_name)
    if adapter is None:
        raise ValueError(f"Node '{node_name}' not found in running circuit")
    adapter.set_routing(config)

    if self._state and node_name in self._state.adapters:
        self._state.adapters[node_name].routing_config = config.model_dump()
        self._state.updated_at = _now_iso()
        save_state(self._state, self.project_dir)

async def restart_service(self, node_name: str) -> None:
    """Restart the service in a node (used by custodian)."""
    if self._state and node_name in self._state.adapters:
        service = self._state.adapters[node_name].service
        if service.command and not service.is_mock:
            await self.slot(node_name, service.command)

def _compute_collapse_level(self) -> CollapseLevel:
    if not self._state or not self._circuit:
        return CollapseLevel.FULL_MOCK
    total = len(self._circuit.nodes)
    live = len(self._state.live_nodes)
    if live == 0:
        return CollapseLevel.FULL_MOCK
    elif live == total:
        return CollapseLevel.FULL_LIVE
    else:
        return CollapseLevel.PARTIAL

def load_manifest(service_dir: str | Path) -> ServiceManifest:
    """Load a ServiceManifest from baton-service.yaml in the given directory."""
    path = Path(service_dir) / MANIFEST_FILENAME
    if not path.exists():
        raise FileNotFoundError(f"No {MANIFEST_FILENAME} found in {service_dir}")
    with open(path) as f:
        raw = yaml.safe_load(f)
    if raw is None:
        raise ValueError(f"Empty {MANIFEST_FILENAME} in {service_dir}")
    return _parse_manifest(raw)

def _parse_manifest(raw: dict) -> ServiceManifest:
    """Parse raw YAML dict into ServiceManifest."""
    deps = []
    for d in raw.get("dependencies", []):
        if isinstance(d, str):
            deps.append(DependencySpec(name=d))
        elif isinstance(d, dict):
            deps.append(DependencySpec(**d))
        else:
            deps.append(d)

    return ServiceManifest(
        name=raw["name"],
        version=raw.get("version", "0.0.0"),
        api_spec=raw.get("api_spec", ""),
        mock_spec=raw.get("mock_spec", ""),
        command=raw.get("command", ""),
        port=raw.get("port", 0),
        proxy_mode=raw.get("proxy_mode", "http"),
        role=raw.get("role", "service"),
        dependencies=deps,
        metadata=raw.get("metadata", {}),
    )

def generate_instance(schema: dict) -> Any:
    """Generate a random valid instance from a JSON Schema."""
    if "example" in schema:
        return schema["example"]
    if "default" in schema:
        return schema["default"]
    if "enum" in schema:
        return schema["enum"][0]

    schema_type = schema.get("type", "object")

    if schema_type == "string":
        fmt = schema.get("format", "")
        if fmt == "date":
            return "2026-01-01"
        if fmt == "date-time":
            return "2026-01-01T00:00:00Z"
        if fmt == "email":
            return "test@example.com"
        if fmt == "uri" or fmt == "url":
            return "https://example.com"
        length = schema.get("minLength", 5)
        return "".join(random.choices(string.ascii_lowercase, k=length))

    if schema_type == "integer":
        lo = schema.get("minimum", 1)
        hi = schema.get("maximum", 100)
        return random.randint(lo, hi)

    if schema_type == "number":
        return round(random.uniform(0, 100), 2)

    if schema_type == "boolean":
        return True

    if schema_type == "array":
        items = schema.get("items", {"type": "string"})
        count = schema.get("minItems", 1)
        return [generate_instance(items) for _ in range(count)]

    if schema_type == "object":
        props = schema.get("properties", {})
        required = set(schema.get("required", list(props.keys())))
        obj = {}
        for name, prop_schema in props.items():
            if name in required:
                obj[name] = generate_instance(prop_schema)
        return obj

    return None

def parse_openapi(spec_path: str) -> dict[str, dict[str, Any]]:
    """Parse an OpenAPI 3.x spec and return route table.

    Returns: {path: {METHOD: response_body}}
    """
    path = Path(spec_path)
    with open(path) as f:
        if path.suffix in (".yaml", ".yml"):
            spec = yaml.safe_load(f)
        else:
            spec = json.load(f)

    if not spec or "paths" not in spec:
        return {}

    components = spec.get("components", {}).get("schemas", {})
    routes: dict[str, dict[str, Any]] = {}

    for path_str, methods in spec["paths"].items():
        routes[path_str] = {}
        for method, operation in methods.items():
            if method.startswith("x-") or method == "parameters":
                continue
            method = method.upper()

            # Find the success response
            responses = operation.get("responses", {})
            success_resp = responses.get("200") or responses.get("201") or {}
            content = success_resp.get("content", {})
            json_content = content.get("application/json", {})
            resp_schema = json_content.get("schema", {})

            # Resolve $ref
            if "$ref" in resp_schema:
                ref_name = resp_schema["$ref"].split("/")[-1]
                resp_schema = components.get(ref_name, {})

            # Generate response body
            if "example" in json_content:
                body = json_content["example"]
            elif "example" in resp_schema:
                body = resp_schema["example"]
            elif resp_schema:
                body = generate_instance(resp_schema)
            else:
                body = {}

            routes[path_str][method] = body

    return routes

def parse_json_schema(spec_path: str) -> dict[str, dict[str, Any]]:
    """Parse a JSON Schema and return a single-endpoint route table."""
    with open(spec_path) as f:
        schema = json.load(f)

    body = generate_instance(schema)
    return {"/": {"GET": body}}

def load_routes(spec_path: str) -> dict[str, dict[str, Any]]:
    """Load routes from a spec file (auto-detect format)."""
    path = Path(spec_path)
    if not path.exists():
        logger.warning(f"Contract spec not found: {spec_path}")
        return {}

    # Try OpenAPI first
    try:
        with open(path) as f:
            if path.suffix in (".yaml", ".yml"):
                data = yaml.safe_load(f)
            else:
                data = json.load(f)
    except Exception:
        return {}

    if isinstance(data, dict) and ("openapi" in data or "paths" in data):
        return parse_openapi(spec_path)
    elif isinstance(data, dict) and ("type" in data or "properties" in data):
        return parse_json_schema(spec_path)
    else:
        return {}

def __init__(self):
    self._route_tables: dict[int, dict[str, dict[str, Any]]] = {}
    self._servers: list[asyncio.Server] = []

def add_routes(self, port: int, routes: dict[str, dict[str, Any]]) -> None:
    """Register routes for a port."""
    self._route_tables[port] = routes

def add_default_routes(self, port: int) -> None:
    """Add a default health endpoint for a port with no contract."""
    self._route_tables[port] = {
        "/": {"GET": {"status": "mock", "port": port}},
        "/health": {"GET": {"status": "ok"}},
    }

async def stop(self, node_name: str, timeout: float = 10.0) -> None:
    """Stop a subprocess gracefully (SIGTERM, then SIGKILL after timeout)."""
    info = self._processes.pop(node_name, None)
    if info is None:
        return
    proc = info.process
    if proc.returncode is not None:
        return  # already exited

    try:
        proc.terminate()
        try:
            await asyncio.wait_for(proc.wait(), timeout=timeout)
        except asyncio.TimeoutError:
            logger.warning(f"Process [{node_name}] pid={info.pid} did not exit, sending SIGKILL")
            proc.kill()
            await proc.wait()
    except ProcessLookupError:
        pass  # already gone
    logger.info(f"Stopped process for [{node_name}]: pid={info.pid}")

def is_running(self, node_name: str) -> bool:
    """Check if a process is still running."""
    info = self._processes.get(node_name)
    if info is None:
        return False
    return info.process.returncode is None

def get_pid(self, node_name: str) -> int | None:
    """Get the PID for a node's process."""
    info = self._processes.get(node_name)
    if info is None:
        return None
    return info.pid

def load_manifests(service_dirs: list[str | Path]) -> list[ServiceManifest]:
    """Load manifests from multiple service directories.

    Validates that all service names are unique.
    """
    manifests = []
    for d in service_dirs:
        manifests.append(load_manifest(d))
    names = [m.name for m in manifests]
    if len(names) != len(set(names)):
        dupes = {n for n in names if names.count(n) > 1}
        raise ValueError(f"Duplicate service names: {dupes}")
    return manifests

def _next_port(used: set[int]) -> int:
    """Find the next available port in the default range."""
    for port in range(DEFAULT_PORT_START, DEFAULT_PORT_MAX + 1):
        if port not in used:
            return port
    raise RuntimeError("No available ports in range")

def ab_split(
    host: str,
    port_a: int,
    port_b: int,
    pct_a: int = 80,
) -> RoutingConfig:
    """Two-target weighted split (A/B test)."""
    return RoutingConfig(
        strategy=RoutingStrategy.WEIGHTED,
        targets=[
            RoutingTarget(name="a", host=host, port=port_a, weight=pct_a),
            RoutingTarget(name="b", host=host, port=port_b, weight=100 - pct_a),
        ],
    )

def canary(
    host: str,
    port_stable: int,
    port_canary: int,
    canary_pct: int = 10,
) -> RoutingConfig:
    """Canary rollout: small percentage to new version."""
    return RoutingConfig(
        strategy=RoutingStrategy.CANARY,
        targets=[
            RoutingTarget(name="stable", host=host, port=port_stable, weight=100 - canary_pct),
            RoutingTarget(name="canary", host=host, port=port_canary, weight=canary_pct),
        ],
    )

def weighted_split(
    targets: list[tuple[str, str, int, int]],
) -> RoutingConfig:
    """N-target weighted split.

    Args:
        targets: List of (name, host, port, weight) tuples.
    """
    return RoutingConfig(
        strategy=RoutingStrategy.WEIGHTED,
        targets=[
            RoutingTarget(name=name, host=host, port=port, weight=weight)
            for name, host, port, weight in targets
        ],
    )

def auto_management_port(self) -> NodeSpec:
    if self.management_port == 0:
        mgmt = self.port + 10000
        if mgmt > 65535:
            mgmt = self.port + 1000
        object.__setattr__(self, "management_port", mgmt)
    return self

def no_self_loop(self) -> EdgeSpec:
    if self.source == self.target:
        raise ValueError(f"Self-loop not allowed: {self.source}")
    return self

def unique_node_names(self) -> CircuitSpec:
    names = [n.name for n in self.nodes]
    if len(names) != len(set(names)):
        dupes = [n for n in names if names.count(n) > 1]
        raise ValueError(f"Duplicate node names: {set(dupes)}")
    return self

def unique_ports(self) -> CircuitSpec:
    ports = [n.port for n in self.nodes]
    if len(ports) != len(set(ports)):
        raise ValueError("Duplicate ports in circuit")
    return self

def egress_not_edge_source(self) -> CircuitSpec:
    egress_names = {n.name for n in self.nodes if n.role == NodeRole.EGRESS}
    for e in self.edges:
        if e.source in egress_names:
            raise ValueError(
                f"Egress node '{e.source}' cannot be an edge source "
                f"(egress nodes are external dependencies, not producers)"
            )
    return self

def edges_reference_existing_nodes(self) -> CircuitSpec:
    names = {n.name for n in self.nodes}
    for e in self.edges:
        if e.source not in names:
            raise ValueError(f"Edge source '{e.source}' not in nodes")
        if e.target not in names:
            raise ValueError(f"Edge target '{e.target}' not in nodes")
    return self

def node_by_name(self, name: str) -> NodeSpec | None:
    for n in self.nodes:
        if n.name == name:
            return n
    return None

def neighbors(self, name: str) -> list[str]:
    """Nodes that this node connects TO."""
    return [e.target for e in self.edges if e.source == name]

def dependents(self, name: str) -> list[str]:
    """Nodes that connect TO this node."""
    return [e.source for e in self.edges if e.target == name]

def ingress_nodes(self) -> list[NodeSpec]:
    """Nodes with ingress role."""
    return [n for n in self.nodes if n.role == NodeRole.INGRESS]

def egress_nodes(self) -> list[NodeSpec]:
    """Nodes with egress role."""
    return [n for n in self.nodes if n.role == NodeRole.EGRESS]

def weights_sum_to_100(self) -> RoutingConfig:
    if self.strategy in (RoutingStrategy.WEIGHTED, RoutingStrategy.CANARY):
        total = sum(t.weight for t in self.targets)
        if total != 100:
            # Allow rollback configs where some targets have weight=0
            non_zero = [t for t in self.targets if t.weight > 0]
            non_zero_total = sum(t.weight for t in non_zero)
            if non_zero_total != 100:
                raise ValueError(
                    f"Weights must sum to 100 for {self.strategy} strategy, got {total}"
                )
    return self

def header_requires_rules(self) -> RoutingConfig:
    if self.strategy == RoutingStrategy.HEADER:
        if not self.rules:
            raise ValueError("Header strategy requires at least one rule")
        if not self.default_target:
            raise ValueError("Header strategy requires a default_target")
    return self

def no_duplicate_target_names(self) -> RoutingConfig:
    names = [t.name for t in self.targets]
    if len(names) != len(set(names)):
        dupes = [n for n in names if names.count(n) > 1]
        raise ValueError(f"Duplicate target names: {set(dupes)}")
    return self

def stop(self) -> None:
    """Signal the run loop to stop."""
    self._running = False

def _collect(self) -> None:
    """Drain signals from all adapters into buffer and JSONL."""
    for adapter in self._adapters.values():
        signals = adapter.drain_signals()
        for sig in signals:
            self._buffer.append(sig)
            append_jsonl(
                self._project_dir,
                SIGNALS_FILE,
                sig.model_dump(),
            )

def query(
    self,
    node: str | None = None,
    path: str | None = None,
    last_n: int = 100,
) -> list[SignalRecord]:
    """Query in-memory buffer."""
    results = list(self._buffer)
    if node:
        results = [s for s in results if s.node_name == node]
    if path:
        results = [s for s in results if path in s.path]
    return results[-last_n:]

def path_stats(self, node: str | None = None) -> dict[str, PathStat]:
    """Per-path aggregation: count, avg_latency, error_rate."""
    signals = list(self._buffer)
    if node:
        signals = [s for s in signals if s.node_name == node]

    stats: dict[str, PathStat] = {}
    totals: dict[str, list[float]] = {}

    for sig in signals:
        if sig.path not in stats:
            stats[sig.path] = PathStat(path=sig.path)
            totals[sig.path] = []
        stats[sig.path].count += 1
        totals[sig.path].append(sig.latency_ms)
        if sig.status_code >= 400:
            stats[sig.path].error_count += 1

    for path, stat in stats.items():
        latencies = totals[path]
        if latencies:
            stat.avg_latency_ms = sum(latencies) / len(latencies)

    return stats

def load_history(
    project_dir: str | Path,
    node: str | None = None,
    last_n: int | None = None,
) -> list[dict]:
    """Read from .baton/signals.jsonl."""
    records = read_jsonl(project_dir, SIGNALS_FILE, last_n=last_n)
    if node:
        records = [r for r in records if r.get("node_name") == node]
    return records

def load_state(project_dir: str | Path) -> CircuitState | None:
    """Load CircuitState from .baton/state.json. Returns None if not found."""
    path = Path(project_dir) / BATON_DIR / STATE_FILE
    if not path.exists():
        return None
    with open(path) as f:
        data = json.load(f)
    return CircuitState(**data)

def clear_state(project_dir: str | Path) -> None:
    """Remove state file."""
    path = Path(project_dir) / BATON_DIR / STATE_FILE
    if path.exists():
        path.unlink()

def read_jsonl(
    project_dir: str | Path, filename: str, last_n: int | None = None
) -> list[dict]:
    """Read JSONL file, optionally last N lines."""
    path = Path(project_dir) / BATON_DIR / filename
    if not path.exists():
        return []
    with open(path) as f:
        lines = f.readlines()
    if last_n is not None:
        lines = lines[-last_n:]
    result = []
    for line in lines:
        line = line.strip()
        if line:
            result.append(json.loads(line))
    return result

def stop(self) -> None:
    """Signal the run loop to stop."""
    self._running = False

def load_history(
    project_dir: str | Path,
    node: str | None = None,
    last_n: int | None = None,
) -> list[dict]:
    """Read back from JSONL. Optional filters."""
    records = read_jsonl(project_dir, METRICS_FILE, last_n=last_n)
    if node:
        filtered = []
        for r in records:
            nodes = r.get("nodes", {})
            if node in nodes:
                filtered.append({
                    "timestamp": r.get("timestamp"),
                    "node": nodes[node],
                })
        return filtered
    return records

def create_provider(name: str) -> DeploymentProvider:
    if name == "local":
        from baton.providers.local import LocalProvider
        return LocalProvider()
    elif name == "gcp":
        from baton.providers.gcp import GCPProvider
        return GCPProvider()
    elif name == "aws":
        from baton.providers.aws import AWSProvider
        return AWSProvider()
    else:
        raise ValueError(f"Unknown provider: {name}. Available: local, gcp, aws")

def _service_id(circuit_name: str, node_name: str, namespace: str) -> str:
    """Generate a Cloud Run service ID from circuit + node name."""
    parts = [namespace, circuit_name, node_name] if namespace else [circuit_name, node_name]
    return "-".join(parts).lower().replace("_", "-")

async def deploy(self, circuit: CircuitSpec, target: DeploymentTarget) -> CircuitState:
    """Deploy each node as a Cloud Run service.

    Required target config:
        project: GCP project ID
    Optional:
        region: GCP region (default: us-central1)
        image_template: Docker image template with {node} placeholder
                       (default: "gcr.io/{project}/{circuit}-{node}:latest")
    """
    try:
        from google.cloud import run_v2
    except ImportError:
        raise RuntimeError(
            "GCP provider requires google-cloud-run. "
            "Install with: pip install baton[gcp]"
        )

    project = target.config.get("project")
    if not project:
        raise ValueError("GCP provider requires 'project' in deployment config")

    region = target.region or "us-central1"
    namespace = target.namespace
    image_template = target.config.get(
        "image_template",
        f"gcr.io/{project}/{circuit.name}-{{node}}:latest",
    )

    # Build images if requested
    if target.config.get("build") == "true":
        from baton.image import ImageBuilder

        project_dir = target.config.get("project_dir", ".")
        builder = ImageBuilder(project_dir, circuit_name=circuit.name)

        for node in circuit.nodes:
            service_dir = (node.metadata or {}).get("service_dir", "")
            if not service_dir:
                logger.warning(
                    f"[{node.name}] No service_dir in metadata, skipping build"
                )
                continue

            tag = image_template.format(node=node.name)
            info = await builder.build(node.name, service_dir, tag=tag)
            await builder.push(tag)
            logger.info(f"Built and pushed [{node.name}]: {tag}")

    client = run_v2.ServicesAsyncClient()
    parent = f"projects/{project}/locations/{region}"

    state = CircuitState(
        circuit_name=circuit.name,
        collapse_level=CollapseLevel.FULL_LIVE,
        started_at=_now_iso(),
        updated_at=_now_iso(),
    )

    # First pass: create/update services
    for node in circuit.nodes:
        service_id = _service_id(circuit.name, node.name, namespace)
        image = image_template.format(node=node.name)

        # Build env vars: inject URLs of neighbor services
        # Note: PORT is reserved by Cloud Run and set automatically
        env_vars = {
            "BATON_NODE_NAME": node.name,
        }

        service = run_v2.Service(
            template=run_v2.RevisionTemplate(
                containers=[
                    run_v2.Container(
                        image=image,
                        ports=[run_v2.ContainerPort(container_port=8080)],
                        env=[
                            run_v2.EnvVar(name=k, value=v)
                            for k, v in env_vars.items()
                        ],
                    )
                ],
            ),
        )

        try:
            operation = await client.create_service(
                parent=parent,
                service=service,
                service_id=service_id,
            )
            result = await operation.result()
            url = result.uri
            self._service_urls[node.name] = url
            logger.info(f"Deployed [{node.name}] as {service_id} -> {url}")
        except Exception as e:
            if "already exists" in str(e).lower():
                # Update existing service
                service.name = f"{parent}/services/{service_id}"
                operation = await client.update_service(service=service)
                result = await operation.result()
                url = result.uri
                self._service_urls[node.name] = url
                logger.info(f"Updated [{node.name}] as {service_id} -> {url}")
            else:
                logger.error(f"Failed to deploy [{node.name}]: {e}")
                state.adapters[node.name] = AdapterState(
                    node_name=node.name,
                    status=NodeStatus.FAULTED,
                )
                continue

        state.adapters[node.name] = AdapterState(
            node_name=node.name,
            status=NodeStatus.ACTIVE,
            service=ServiceSlot(
                command=image,
                is_mock=False,
                started_at=_now_iso(),
            ),
        )
        state.live_nodes.append(node.name)

    # Make all services publicly accessible
    for node in circuit.nodes:
        service_id = _service_id(circuit.name, node.name, namespace)
        try:
            from google.iam.v1 import policy_pb2

            resource = f"{parent}/services/{service_id}"
            policy = policy_pb2.Policy(
                bindings=[
                    policy_pb2.Binding(
                        role="roles/run.invoker",
                        members=["allUsers"],
                    )
                ]
            )
            await client.set_iam_policy(
                request={"resource": resource, "policy": policy}
            )
        except Exception as e:
            logger.warning(f"Could not set IAM policy for [{node.name}]: {e}")

    # Second pass: inject neighbor URLs as env vars
    if self._service_urls:
        for node in circuit.nodes:
            neighbors = circuit.neighbors(node.name)
            if not neighbors:
                continue

            neighbor_env = {}
            for nb in neighbors:
                url = self._service_urls.get(nb)
                if url:
                    env_key = f"BATON_{nb.upper().replace('-', '_')}_URL"
                    neighbor_env[env_key] = url

            if not neighbor_env:
                continue

            service_id = _service_id(circuit.name, node.name, namespace)
            image = image_template.format(node=node.name)

            all_env = {"BATON_NODE_NAME": node.name}
            all_env.update(neighbor_env)

            service = run_v2.Service(
                name=f"{parent}/services/{service_id}",
                template=run_v2.RevisionTemplate(
                    containers=[
                        run_v2.Container(
                            image=image,
                            ports=[run_v2.ContainerPort(container_port=8080)],
                            env=[
                                run_v2.EnvVar(name=k, value=v)
                                for k, v in all_env.items()
                            ],
                        )
                    ],
                ),
            )

            try:
                operation = await client.update_service(service=service)
                await operation.result()
                logger.info(
                    f"Updated [{node.name}] with neighbor URLs: "
                    f"{list(neighbor_env.keys())}"
                )
            except Exception as e:
                logger.warning(
                    f"Could not update [{node.name}] with neighbor URLs: {e}"
                )

    state.updated_at = _now_iso()
    return state

def __init__(self) -> None:
    self._mgr: LifecycleManager | None = None
    self._mock_server = None

async def status(self, circuit: CircuitSpec, target: DeploymentTarget) -> CircuitState:
    """Return current state of local deployment."""
    if self._mgr and self._mgr.state:
        return self._mgr.state
    return CircuitState(
        circuit_name=circuit.name,
        collapse_level=CollapseLevel.FULL_MOCK,
    )
